import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface UpcomingTrip {
  destination: string;
  departureDate: string;
  countdownDays: number;
}

interface PackingList {
  totalItems: number;
  packedItems: number;
  progress: number;
}

interface TravelData {
  upcomingTrip: UpcomingTrip;
  packingList: PackingList;
}

export default function Widget() {
  const travelData = response.data as TravelData;
  const { upcomingTrip, packingList } = travelData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={700} sx={{ mb: 1 }}>
              Upcoming Trip
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Destination: {upcomingTrip.destination}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Departure: {new Date(upcomingTrip.departureDate).toLocaleDateString()}
            </Typography>
            <Typography variant="h4" sx={{ mt: 1, color: '#4CAF50', fontWeight: 600 }}>
              {upcomingTrip.countdownDays} days to go
            </Typography>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={700} sx={{ mb: 1 }}>
              Packing Progress
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Packed {packingList.packedItems} of {packingList.totalItems} items
            </Typography>
            <LinearProgress
              variant="determinate"
              value={packingList.progress}
              sx={{
                height: 8,
                borderRadius: 4,
                mt: 1,
                bgcolor: '#E0E0E0',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#4CAF50',
                  borderRadius: 4,
                }
              }}
            />
            <Typography variant="body2" fontWeight={500} sx={{ mt: 1, color: '#FFC107' }}>
              {packingList.progress}%
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
